import{_ as a,o,c as t,a0 as i}from"./chunks/framework.BjpW4enL.js";const p=JSON.parse('{"title":"NEXUS Architecture Map (v3.6: Multi-Modal Edition)","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_reports/ARCHITECTURE_TOUR.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_reports/ARCHITECTURE_TOUR.md","lastUpdated":1783623176000}'),s={name:"Z_Archive/wiki_legacy/archive/legacy_reports/ARCHITECTURE_TOUR.md"};function r(n,e,d,l,c,u){return o(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="nexus-architecture-map-v3-6-multi-modal-edition" tabindex="-1">NEXUS Architecture Map (v3.6: Multi-Modal Edition) <a class="header-anchor" href="#nexus-architecture-map-v3-6-multi-modal-edition" aria-label="Permalink to &quot;NEXUS Architecture Map (v3.6: Multi-Modal Edition)&quot;">​</a></h1><p>&gt; <strong>Status editorial:</strong> panorama humano de leitura rápida. &gt; Não deve ser tratado como fonte normativa final. &gt; Em caso de conflito, prevalecem: &gt; <a href="/var/home/bruno/NEXUS/docs/CANONICAL_ARCHITECTURE.html">CANONICAL_ARCHITECTURE.md</a>, &gt; <a href="/var/home/bruno/NEXUS/docs/CANONICAL_RUNTIME.html">CANONICAL_RUNTIME.md</a> &gt; e <a href="/var/home/bruno/NEXUS/docs/architecture_decisions/">architecture_decisions/INDEX.md</a>.</p><h2 id="the-axiomatic-stack" tabindex="-1">The Axiomatic Stack <a class="header-anchor" href="#the-axiomatic-stack" aria-label="Permalink to &quot;The Axiomatic Stack&quot;">​</a></h2><p>O sistema NEXUS opera num pipeline multidimensional, fatiando a informação do disco físico para as dimensões conceituais através do Coordinator (Rust). O sistema evoluiu além de text embeddings para englobar Árvores de Sintaxe Abstratas (AST).</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T1 (Flesh)  → T2 (Blood)   → T3 (Ghost/AST) → T4 (Graph)   → T5 (Whisper)  → T6 (Time)</span></span>
<span class="line"><span>Filesystem    PostgreSQL     Qdrant Spaces    k-NN Links     Reflections     Temporal Diffs</span></span></code></pre></div><hr><h2 id="t1-flesh-filesystem" tabindex="-1">T1: Flesh (Filesystem) <a class="header-anchor" href="#t1-flesh-filesystem" aria-label="Permalink to &quot;T1: Flesh (Filesystem)&quot;">​</a></h2><p><strong>O Corpo Físico.</strong> Arquivos raw (código e markdowns) mapeados em <code>/data</code>.</p><ul><li><strong>Identity Anchor:</strong> Path absoluto com hash de arquivo para ignorar scans inúteis (Cache Deduplication).</li><li>O <code>node_modules</code>, <code>.git</code>, e <code>archives</code> do próprio Qdrant/Ollama são sistematicamente vetados pela indexação do Rust.</li></ul><hr><h2 id="t2-blood-postgresql" tabindex="-1">T2: Blood (PostgreSQL) <a class="header-anchor" href="#t2-blood-postgresql" aria-label="Permalink to &quot;T2: Blood (PostgreSQL)&quot;">​</a></h2><p><strong>A Memória Episódica (Relacional).</strong> A fonte de verdade imutável.</p><ul><li><strong><code>fs_nodes</code>:</strong> O estado do sistema de arquivos (<code>path</code>, <code>content_hash</code>, <code>last_ingested_at</code>).</li><li><strong><code>blobs</code>:</strong> Versionamento da Estratégia C. Todo update de arquivo vira um clone novo, deprecando a versão velha (<code>is_current = false</code>).</li><li><strong><code>abstractions</code>:</strong> O fracionamento lógico. <ul><li><strong>Level 0:</strong> Chunks de texto semântico (2500 chars).</li><li><strong>Level 5 (Novo v3.6):</strong> Nós da AST puros (Árvore Sintática). Funções e Classes desossadas sem contexto coloquial, mantendo assinaturas e tipos explícitos para roteamento vetorial.</li></ul></li><li><strong>AIE (Asynchronous Index Enrichment):</strong> A coluna <code>enriched</code>. Chunks recebem descrições semânticas em background via LLM para transmutar sintaxe em conhecimento falado.</li></ul><hr><h2 id="t3-the-parallel-latent-spaces-qdrant" tabindex="-1">T3: The Parallel Latent Spaces (Qdrant) <a class="header-anchor" href="#t3-the-parallel-latent-spaces-qdrant" aria-label="Permalink to &quot;T3: The Parallel Latent Spaces (Qdrant)&quot;">​</a></h2><p><strong>O Roteador Multi-Dimensional.</strong> Vetores não mais se misturam. A sintaxe é isolada do texto explicativo.</p><ul><li><strong>nexus_ghost:</strong> Saguão Semântico. 768 dimensões via <code>nomic-embed-text</code>. Para as <code>abstractions</code> L0. Atrai buscas conceituais (ex: &quot;Onde tratamos erros de banco?&quot;).</li><li><strong>nexus_ast:</strong> Matriz Estrutural. 1024 dimensões via <code>bge-m3</code> (Multilingual Code). Exclusivo para as assinaturas L5. Atrai buscas determinísticas de código (&quot;Extract function defs&quot;).</li></ul><hr><h2 id="t4-topology-postgresql-links" tabindex="-1">T4: Topology (PostgreSQL Links) <a class="header-anchor" href="#t4-topology-postgresql-links" aria-label="Permalink to &quot;T4: Topology (PostgreSQL Links)&quot;">​</a></h2><p><strong>O Motor de Vizinhança Esparsa.</strong> Evita isolamento vetorial, mas nao deve ser confundido com a forma final da memoria.</p><ul><li><strong>Aresta <code>hilbert_bridge</code>:</strong> Grafo K-NN (K-Nearest Neighbors). Usa o índice HNSW do Qdrant para criar pontes ($O(K \\log N)$) baseadas em proximidade de embeddings.</li><li><strong>Aresta <code>references</code>:</strong> Ponte lexical legada. Pode existir historicamente no banco, mas não faz parte do PPR ativo do runtime v3.9.</li><li><strong>Querying (T-RAG):</strong> O sistema localiza a semente no Qdrant e caminha pelo subgrafo ativo do Postgres (<code>hilbert_bridge</code> + <code>supersedes</code> quando presente).</li><li><strong>Direção de refatoração:</strong> O T4 atual é um estágio intermediário. O alvo é uma camada de navegação semântica supra-index, alimentada por Qdrant e Postgres, mas não reduzida a PageRank relacional.</li></ul><hr><h2 id="t5-whisper-reflections" tabindex="-1">T5: Whisper (Reflections) <a class="header-anchor" href="#t5-whisper-reflections" aria-label="Permalink to &quot;T5: Whisper (Reflections)&quot;">​</a></h2><p><strong>A Sub-Consciência do Sistema.</strong></p><ul><li>A cada <code>REFLECT_THRESHOLD</code> de inserções, o sistema sintetiza suas próprias deduções e armazena os insights no relacional.</li></ul><hr><h2 id="t6-time-temporal-context-window" tabindex="-1">T6: Time (Temporal Context Window) <a class="header-anchor" href="#t6-time-temporal-context-window" aria-label="Permalink to &quot;T6: Time (Temporal Context Window)&quot;">​</a></h2><p><strong>A Onisciência Cronológica.</strong></p><ul><li><strong>O Problema:</strong> Fornecer múltiplas versões do mesmo código causa alucinação.</li><li><strong>A Solução:</strong> O <code>scripts/temporal_context.py</code> usa diffs unificados (Git-style) para provar &quot;o que mudou&quot;, em vez de &quot;o que é&quot;. A evolução cronológica é cruzada para dezenas de arquivos num eixo único.</li></ul><hr><h2 id="a-pipeline-hibrida-hyde-aie" tabindex="-1">A Pipeline Híbrida (HyDE &amp; AIE) <a class="header-anchor" href="#a-pipeline-hibrida-hyde-aie" aria-label="Permalink to &quot;A Pipeline Híbrida (HyDE &amp; AIE)&quot;">​</a></h2><p>Para vencer os limites matemáticos de RAG puros (Taxa de acerto cega de 46%), implementamos:</p><ol><li><strong>HyDE Fusion:</strong> Hoje ocorre client-side via <code>scripts/trag_query.py</code>, concatenando keywords técnicas antes da chamada ao <code>/query</code>. Não é uma transformação nativa do endpoint do coordinator.</li><li><strong>Payload Filtering (<code>ext</code>):</strong> O T2 (Postgres) destrói markdowns &quot;buracos-negros&quot; na hora da busca aplicando <code>LIKE &#39;%.rs&#39;</code> caso o humano esteja procurando código-fonte, garantindo exclusividade de sintaxe.</li></ol>`,33)])])}const h=a(s,[["render",r]]);export{p as __pageData,h as default};
